from collections import deque

class MovingAverage:
    def __init__(self, window):
        if window <= 0:
            raise ValueError('window must be positive')
        self.window = window
        self.q = deque()
        self.total = 0.0
    def add(self, x):
        self.q.append(x)
        self.total += x
        if len(self.q) > self.window:
            self.total -= self.q.popleft()
    def value(self):
        if not self.q:
            return 0.0
        return self.total / len(self.q)

