def percentile(values, p):
    if not values:
        raise ValueError('empty input')
    if not (0 <= p <= 100):
        raise ValueError('p must be in [0, 100]')
    s = sorted(values)
    n = len(s)
    idx = (n - 1) * p / 100.0
    lo = int(idx)
    hi = lo + 1
    if hi >= n:
        return float(s[lo])
    frac = idx - lo
    return s[lo] + (s[hi] - s[lo]) * frac

