import time
from functools import wraps

def with_retry(attempts=3, initial_delay=0.01, factor=2, exceptions=(Exception,), sleeper=time.sleep):
    def deco(fn):
        @wraps(fn)
        def wrapper(*args, **kwargs):
            delay = initial_delay
            for i in range(attempts):
                try:
                    return fn(*args, **kwargs)
                except exceptions:
                    if i == attempts - 1:
                        raise
                    sleeper(delay)
                    delay *= factor
        return wrapper
    return deco

