from functools import wraps

def memoize(maxsize):
    def deco(fn):
        cache = OrderedDict()
        stats = {'hits': 0, 'misses': 0}
        @wraps(fn)
        def wrapper(*args):
            if args in cache:
                stats['hits'] += 1
                return cache[args]
            stats['misses'] += 1
            val = fn(*args)
            cache[args] = val
            if len(cache) > maxsize:
                cache.popitem(last=False)  # FIFO: evict the oldest
            return val
        wrapper.cache_info = lambda: {'hits': stats['hits'], 'misses': stats['misses'], 'currsize': len(cache)}
        return wrapper
    return deco

