def sliding_max(values, k):
    if k <= 0 or len(values) < k:
        return []
    out = []
    dq = deque()  # holds indices, values[dq[0]] is current window max
    for i, v in enumerate(values):
        # Drop indices outside the window
        while dq and dq[0] <= i - k:
            dq.popleft()
        # Maintain monotone decreasing: drop smaller-or-equal from the back
        while dq and values[dq[-1]] <= v:
            dq.pop()
        dq.append(i)
        if i >= k - 1:
            out.append(values[dq[0]])
    return out

