from collections import deque

class RecentDistinct:
    def __init__(self, window_s):
        self.window_s = window_s
        self.events = deque()  # (item, ts)
        self.counts = {}       # item -> count in current window
        self.now = None
    def _expire(self):
        cutoff = self.now - self.window_s
        while self.events and self.events[0][1] <= cutoff:
            item, _ = self.events.popleft()
            self.counts[item] -= 1
            if self.counts[item] == 0:
                del self.counts[item]
    def add(self, item, ts):
        self.now = ts
        self.events.append((item, ts))
        self.counts[item] = self.counts.get(item, 0) + 1
        self._expire()
    def count(self):
        if self.now is None:
            return 0
        self._expire()
        return len(self.counts)

