def shortest_path(graph, start, end):
    if start == end:
        return [start]
    if start not in graph:
        return []
    visited = {start}
    parent = {start: None}
    q = deque([start])
    while q:
        node = q.popleft()
        for nb in graph.get(node, []):
            if nb in visited:
                continue
            visited.add(nb)
            parent[nb] = node
            if nb == end:
                # Reconstruct path
                path = [end]
                while parent[path[-1]] is not None:
                    path.append(parent[path[-1]])
                return list(reversed(path))
            q.append(nb)
    return []

