def first_missing_positive(nums):
    n = len(nums)
    if n == 0:
        return 1
    # Place each value v (1 <= v <= n) at index v-1 via cyclic swaps.
    i = 0
    while i < n:
        v = nums[i]
        if 1 <= v <= n and nums[v - 1] != v:
            nums[i], nums[v - 1] = nums[v - 1], nums[i]
        else:
            i += 1
    # First index where nums[i] != i+1 is the answer.
    for i in range(n):
        if nums[i] != i + 1:
            return i + 1
    return n + 1

