        return ''
    def expand(lo, hi):
        while lo >= 0 and hi < len(s) and s[lo] == s[hi]:
            lo -= 1
            hi += 1
        return lo + 1, hi  # half-open [lo+1, hi)
    best_lo, best_hi = 0, 1
    for i in range(len(s)):
