class BST:
    def __init__(self):
        self.root = None
    def insert(self, value):
        def _insert(node):
            if node is None:
                return {'val': value, 'left': None, 'right': None}
            if value < node['val']:
                node['left'] = _insert(node['left'])
            elif value > node['val']:
                node['right'] = _insert(node['right'])
            # value == node['val']: silently ignore (no duplicate)
            return node
        self.root = _insert(self.root)
    def contains(self, value):
        n = self.root
        while n is not None:
            if value == n['val']:
                return True
            n = n['left'] if value < n['val'] else n['right']
        return False
    def inorder(self):
        out = []
        def visit(n):
            if n is None:
                return
            visit(n['left'])
            out.append(n['val'])
            visit(n['right'])
        visit(self.root)
        return out

