def cache_with_ttl(ttl_seconds, clock=time.monotonic):
    def deco(fn):
        store = {}
        @functools.wraps(fn)
        def wrapper(*args):
            now = clock()
            if args in store:
                value, ts = store[args]
                if now - ts <= ttl_seconds:
                    return value
            value = fn(*args)
            store[args] = (value, now)
            return value
        return wrapper
