        return 0
    i, j = 0, len(heights) - 1
    best = 0
    while i < j:
        h = min(heights[i], heights[j])
        area = h * (j - i)
        if area > best:
            best = area
        # Move the SHORTER side inward — it limits the area
        if heights[i] < heights[j]:
            i += 1
        else:
            j -= 1
    return best

