    def score(values, reverse):
        order = sorted(range(len(values)), key=lambda i: (values[i], i), reverse=reverse)
        n = len(values)
        s = [0] * n
        for rank, idx in enumerate(order):
            s[idx] = rank * 4 // n + 1
        return s
