    pre_users = set()
    active_in_window = set()
    for user_id, d in activity:
        dd = date.fromisoformat(d)
        if dd <= cut:
            pre_users.add(user_id)
        if cut < dd <= horizon_end:
            active_in_window.add(user_id)
    return {u: (0 if u in active_in_window else 1) for u in pre_users}

